// // This module filters packets based on the source and destination IP addresses.
// It accepts packets only if the source IP is outside the range 00000 to 01111 and the destination IP is not 10101.
module packet_filter (
    input [4:0] src_ip,
    input [4:0] dest_ip,
    output reg accept
);

always @(*) begin
    if ((src_ip >= 5'b00000 && src_ip <= 5'b01111) && (dest_ip == 5'b10101)) 
        accept = 1'b1; // Accept the packet
    else 
        accept = 1'b0; // Reject the packet
end

endmodule
